section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-documentation.json",
  "title": "API Documentation",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "publisher",
    "sections",
    "examples_per_endpoint",
    "error_catalogue_ref",
    "changelog_url",
    "freshness_check",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug",
      "minLength": 1
    },
    "publisher": {
      "type": "string",
      "description": "docs platform (redocly, mintlify, scalar, mkdocs)",
      "minLength": 1
    },
    "sections": {
      "type": "array",
      "description": "ordered list of section ids: [quick-start, auth, endpoints, errors, sdks, changelog, support]",
      "minItems": 1
    },
    "examples_per_endpoint": {
      "type": "integer",
      "description": "minimum 2 examples per endpoint (happy + at least one error)"
    },
    "error_catalogue_ref": {
      "type": "string",
      "description": "path or URL to the canonical error catalogue",
      "minLength": 1
    },
    "changelog_url": {
      "type": "string",
      "description": "URL of the API changelog",
      "minLength": 1
    },
    "freshness_check": {
      "type": "string",
      "description": "CI doc-test name + cadence",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
